using System.ComponentModel;
using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ────────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// Shared state for the note-taking tool
var notes = new List<(string Title, string Content)>();

// ── Build the IChatClient with function-invocation middleware ─────────
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// ── Define tools ─────────────────────────────────────────────────────
var tools = new List<AITool>
{
    AIFunctionFactory.Create(SearchWebAsync, "SearchWeb",
        "Search the web for information on a query. Returns relevant snippets."),
    AIFunctionFactory.Create(FetchPageAsync, "FetchPage",
        "Fetch and read the text content of a web page at a given URL."),
    AIFunctionFactory.Create(
        ([Description("Short descriptive title")] string title,
         [Description("The note content")] string content) =>
        {
            notes.Add((title, content));
            Log($"📝 Note saved: {title}");
            return $"Note saved: \"{title}\" (total notes: {notes.Count})";
        },
        "TakeNote",
        "Save a research note with a title and content for later reference."),
    AIFunctionFactory.Create(() =>
        {
            if (notes.Count == 0)
                return "No notes saved yet.";
            return string.Join("\n\n---\n\n",
                notes.Select((n, i) => $"[Note {i + 1}] {n.Title}\n{n.Content}"));
        },
        "GetNotes",
        "Retrieve all research notes saved so far."),
};

// ── Create the agent ─────────────────────────────────────────────────
var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and taking notes.",
    instructions: """
        You are a thorough research assistant. When given a topic:
        1. Use SearchWeb to find information from multiple angles (at least 3 searches).
        2. Use FetchPage to read promising web pages for more detail when needed.
        3. Use TakeNote to record key findings as you go — organize by sub-topic.
        4. Use GetNotes to review what you have collected so far.
        5. Synthesize everything into a well-structured final summary with key facts,
           different perspectives, and source URLs where possible.
        Be methodical: search broadly first, then dive deeper into the most relevant results.
        """,
    tools: tools);

// ── Interactive loop ─────────────────────────────────────────────────
Console.WriteLine("🔬 Research Agent");
Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine("Enter a research topic, or type 'quit' to exit.\n");

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic ▸ ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) ||
        topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        break;
    }

    Console.WriteLine($"\n🔍 Researching: {topic}\n");

    try
    {
        var session = await agent.CreateSessionAsync();
        var response = await agent.RunAsync(
            $"Please research the following topic and provide a comprehensive summary:\n\n{topic}",
            session);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("\n📋 Research Summary");
        Console.WriteLine("───────────────────────────────────────────");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"\nError: {ex.Message}");
        Console.ResetColor();
        Console.WriteLine();
    }

    notes.Clear();
}

Console.WriteLine("Goodbye! 👋");
return;

// ── Tool implementations ─────────────────────────────────────────────

async Task<string> SearchWebAsync(
    [Description("The search query")] string query)
{
    Log($"🌐 Searching: \"{query}\"");

    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
    http.Timeout = TimeSpan.FromSeconds(15);

    var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}" +
              "&format=json&no_html=1&t=ResearchAgent";
    try
    {
        var json = await http.GetStringAsync(url);
        using var doc = JsonDocument.Parse(json);
        var root = doc.RootElement;
        var results = new List<string>();

        // Instant-answer abstract
        if (root.TryGetProperty("Abstract", out var abs) &&
            abs.GetString() is { Length: > 0 } abstractText)
        {
            var source = root.TryGetProperty("AbstractSource", out var src)
                ? src.GetString() : null;
            var link = root.TryGetProperty("AbstractURL", out var aUrl)
                ? aUrl.GetString() : null;
            results.Add($"[{source ?? "Summary"}] {abstractText}" +
                         (link != null ? $"\n  Source: {link}" : ""));
        }

        // Related topics
        if (root.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var t in topics.EnumerateArray().Take(8))
            {
                if (t.TryGetProperty("Text", out var text) &&
                    text.GetString() is { Length: > 0 } snippet)
                {
                    var firstUrl = t.TryGetProperty("FirstURL", out var u)
                        ? u.GetString() : null;
                    results.Add(firstUrl != null
                        ? $"{snippet}\n  URL: {firstUrl}" : snippet);
                }
                else if (t.TryGetProperty("Topics", out var subTopics))
                {
                    foreach (var sub in subTopics.EnumerateArray().Take(3))
                    {
                        if (sub.TryGetProperty("Text", out var st) &&
                            st.GetString() is { Length: > 0 } subText)
                        {
                            results.Add(subText);
                        }
                    }
                }
            }
        }

        return results.Count > 0
            ? string.Join("\n\n", results)
            : "No results found. Try rephrasing the query or being more specific.";
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}. Try a different query.";
    }
}

async Task<string> FetchPageAsync(
    [Description("The URL of the web page to fetch")] string url)
{
    Log($"📄 Fetching: {url}");

    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
    http.Timeout = TimeSpan.FromSeconds(15);

    try
    {
        var html = await http.GetStringAsync(url);

        // Strip script/style blocks, then remaining HTML tags
        var text = Regex.Replace(html, @"<(script|style)[^>]*>.*?</\1>", " ",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);
        text = Regex.Replace(text, "<[^>]+>", " ");
        text = System.Net.WebUtility.HtmlDecode(text);
        text = Regex.Replace(text, @"\s+", " ").Trim();

        const int maxLen = 4000;
        return text.Length > maxLen
            ? text[..maxLen] + "\n\n[Content truncated]"
            : text;
    }
    catch (Exception ex)
    {
        return $"Failed to fetch page: {ex.Message}";
    }
}

void Log(string message)
{
    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"  {message}");
    Console.ResetColor();
}

